import "@typespec/http";
using TypeSpec.Http;
namespace Features;
interface FeatureOperations {
  @patch @route("/{featureId}") @operationId("update-feature")
  @extension(Shared.UnstableExtension, true)
  update(@path featureId: Shared.ULID, @body feature: FeatureUpdateRequest): Shared.UpdateResponse<Feature> | Common.ErrorResponses | Common.NotFound;
}

// governance.tsp
enum GovernanceFeatureAccessReasonCode {
  Unknown: "unknown",
  UsageLimitReached: "usage_limit_reached",
  FeatureUnavailable: "feature_unavailable",
  FeatureNotFound: "feature_not_found",
  NoCreditAvailable: "no_credit_available",
  EntitlementExpired: "entitlement_expired",
}

@friendlyName("BillingPartyAddresses")
model BillingPartyAddresses {
  billing_address: Shared.Address;
  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  shipping_address?: Shared.Address;
}
